16	export class CommentsComponent implements OnInit {
17	  @Input() itemHeaderId: number
18	  @Output() loaded = new EventEmitter<boolean>();
19	
20	  comments: CommentInterface[] = [];
21	  rootComments: CommentInterface[] = [];
