38	  getComments() {
39	    this.itemService.getComments(this.itemHeaderId).subscribe({
40	      next: (data) => {
41	        this.comments = data.map(item => ({
42	          id: item.id,
43	          comment: item.comment,
44	          item_header_id: item.item_header_id,
45	          user_id: item.user_id,
46	          user_name: item.users.length > 0 ? item.users[0].name : '',
47	          author_photo: item.author_photo ?? null,
48	          parent_id: item.parent_id,
49	          inserted_date: this.getFormattedDate(item.inserted_date),
50	          attachments: item.itemAttachments.map(a => ({
51	            attachment_link: a.attachment_link,
52	            item_attachment_fileName: a.item_attachment_fileName
53	          }))
54	        }));
55	      },
56	      error: (err) => console.error(err),
57	      complete: () => this.loaded.emit(true)
58	    });
59	  }
60	
61	  getRootComments(): CommentInterface[] {
62	    return this.comments.filter((comment) => comment.parent_id === null);
63	  }
64	
65	  addComment(form: any) {
66	    const comment: CommentInterface = {
67	      comment: form.text,
68	      item_header_id: this.itemHeaderId,
69	      user_id: this.userInfo.userid,
70	      parent_id: form.parentId
71	    }
72	    this.itemService.addComment(comment).subscribe(data => {
73	      const commentId = data.id;
74	      if (form.files.length > 0) {
75	        this.addAttachments(commentId, form.files)
76	      } else {
77	        this.getComments()
78	      }
79	      this.activeComment = null;
80	    })
81	  }
