83	  updateComment(form: any) {
84	    this.itemService.updateComment(form.commentId, form.text).subscribe(data => {
85	      if (form.files.length > 0) {
86	        this.addAttachments(form.commentId, form.files)
87	      } else {
88	        this.getComments()
89	      }
90	      this.getReplies(form.commentId)
91	      this.activeComment = null;
92	    })
93	  }
