95	  addAttachments(commentId: number, files: any[]) {
96	    const fileCount = files.length;
97	    this.loading = true
98	    let href = document.location.href.split('/');
99	    const itemId = +href[href.length - 1];
100	
101	    // Iterate through each file in the files array
102	    for (let i = 0; i < fileCount; i++) {
103	      const file: File = files[i];
104	      const contentType = file.type;
105	      const fileName = `comments-${new Date().getTime()}-${file.name.toLowerCase()}`;
106	
107	      // Obtain the pre-signed URL for the current file
108	      this.itemService.getPreSignedUrl({ fileName, contentType })
109	        .subscribe((res: { signedUrl: string }) => {
110	          const signedUrl = res.signedUrl;
111	          const headers = new Headers({ 'Content-Type': contentType, 'x-amz-acl': 'public-read' });
112	          const putConfig = { method: 'PUT', body: file, headers: headers };
113	
114	          // Upload the file to the cloud storage using the signed URL
115	          fetch(signedUrl, putConfig)
116	            .then(output => {
117	              const body = {
118	                flag: 'comment-create-edit',
119	                item_num_id_fk: itemId,
120	                attachment_type: contentType,
121	                attachment_display_name: contentType.split("/")[0],
122	                fileName,
123	                comment_id: commentId
124	              };
125	              // Save the file link to your database
126	              this.itemService.saveTechLink(body, itemId)
127	                .pipe(take(1))
128	                .subscribe((res) => {
129	                  this.getComments()
130	                  if (i === 0) {
131	                    this.loading = false
132	                    this.childComponent.resetFileInput();
133	                  }
134	                })
135	            }).catch(error => {
136	              this.loading = false;
137	            });
138	        });
139	    }
140	  }
141	
142	  deleteComment(commentId: number): void {
143	    this.itemService.deleteComment(commentId).subscribe(() => {
144	      this.comments = this.comments.filter(
145	        (comment) => comment.id !== commentId
146	      );
147	    });
148	  }
149	
150	  getReplies(commentId: number): CommentInterface[] {
151	    return this.comments
152	      .filter(comment => comment.parent_id === commentId)
153	      .sort((a, b) => new Date(a.inserted_date).getTime() - new Date(b.inserted_date).getTime());
154	  }
155	
156	  setActiveComment(activeComment: ActiveCommentInterface | null): void {
157	    this.activeComment = activeComment;
158	  }
