160	  getUserInfo() {
161	    const token = localStorage.getItem('token');
162	    if (token) {
163	      const tokenPayload = <any>decode(token);
164	      this.userInfo = {
165	        userid: tokenPayload.user_id,
166	        name: tokenPayload.name,
167	        email: tokenPayload.email
168	      }
169	    }
170	  }
171	
172	  getFormattedDate(inserted_date) {
173	    // Convert inserted_date to MM/DD/YY HH:MM:SS format
174	    const dateObj = new Date(inserted_date);
175	    const month = (dateObj.getMonth() + 1).toString().padStart(2, '0'); // Month is 0-based
176	    const day = dateObj.getDate().toString().padStart(2, '0');
177	    const year = dateObj.getFullYear().toString().slice(-2); // Get the last two digits of the year
178	    const hours = dateObj.getHours().toString().padStart(2, '0');
179	    const minutes = dateObj.getMinutes().toString().padStart(2, '0');
180	    const seconds = dateObj.getSeconds().toString().padStart(2, '0');
181	
182	    const formattedDate = `${month}/${day}/${year} ${hours}:${minutes}:${seconds}`;
183	    return formattedDate
184	  }
185	}

