53	  ngOnInit(): void {
54	    this.form = this.fb.group({
55	      title: [this.initialText, Validators.required],
56	    });
57	
58	    this.mentionSub = this.notificationService
59	      .getMentionableUsers()
60	      .subscribe({
61	        next: (res) => { this.mentionUsers = res?.data ?? []; },
62	        error: () => {},
63	      });
